/**
 * @traqr/core — Configuration Schema
 *
 * Types, defaults, and starter packs for the Traqr platform.
 * Stored at .traqr/config.json in each project.
 * Generated by /traqr-init, read by all commands.
 */

// ============================================================
// Daemon & Guardian Configuration
// ============================================================

/**
 * Daemon orchestration configuration.
 * Controls polling intervals, timeouts, concurrency, retry strategies,
 * and file paths for the daemon process.
 *
 * All timing values are in milliseconds.
 */
export interface DaemonConfig {
  /** API base URL for daemon coordination endpoints */
  apiBase: string;

  /** Temporary file paths used by daemon for state persistence */
  paths: {
    /** Processed Slack messages tracking */
    processed: string;
    /** Processed Linear issues tracking */
    processedIssues: string;
    /** Plan approval state */
    plans: string;
    /** Claude question queue */
    questionQueue: string;
    /** Answered questions log */
    answeredQuestions: string;
    /** Processed analytics events */
    processedAnalytics: string;
    /** Automation metrics */
    metrics: string;
    /** Guardian temporary working directory (relative to worktrees base) */
    guardianTemp: string;
  };

  /** Polling intervals (ms) */
  intervals: {
    /** Main loop poll interval (default: 10s) */
    poll: number;
    /** Supabase task queue poll interval (default: 30s) */
    taskPoll: number;
    /** Guardian merge loop interval (default: 30s) */
    guardian: number;
    /** Slack question check interval (default: 60s) */
    question: number;
    /** Analytics processing interval (default: 60s) */
    analytics: number;
    /** Plan approval check interval (default: 30s) */
    approvalCheck: number;
    /** Traffic monitoring interval (default: 15min) */
    trafficCheck: number;
    /** Health check interval when idle (default: 30min) */
    healthCheck: number;
    /** Slot sync check interval (default: 30s) */
    syncCheck: number;
    /** Agent heartbeat interval (default: 60s) */
    heartbeat: number;
  };

  /** Timeout values (ms) */
  timeouts: {
    /** Default fetch timeout (default: 30s) */
    defaultFetch: number;
    /** Quick fetch timeout for non-critical requests (default: 3s) */
    quickFetch: number;
    /** Git operation timeout (default: 30s) */
    git: number;
    /** Quick git operations like status/branch (default: 5s) */
    gitQuick: number;
    /** Git worktree removal timeout (default: 15s) */
    gitRemove: number;
    /** Plan approval wait timeout (default: 5min) */
    planApproval: number;
    /** Maximum implementation time (default: 30min) */
    implementation: number;
    /** Stall detection for tool calls (default: 5min) */
    toolCallStall: number;
    /** npm build timeout (default: 2min) */
    npmBuild: number;
    /** Plan approval TTL before auto-expiry (default: 24h) */
    planApprovalTTL: number;
    /** Pause/hold expiration time (default: 2h) */
    pauseExpiration: number;
    /** Window for detecting rework cycles (default: 30min) */
    reworkDetection: number;
    /** Adaptive timeout per changed file (default: 3min) */
    perFileAdaptive: number;
    /** Maximum adaptive timeout cap (default: 30min) */
    maxAdaptive: number;
    /** Divergence check cache TTL (default: 25s) */
    divergenceCache: number;
    /** Minimum wait before checking approval (default: 30s) */
    minApprovalWait: number;
  };

  /** Concurrency and failure limits */
  concurrency: {
    /** Maximum concurrent tasks (Walk=2, Run=all slots) */
    maxTasks: number;
    /** Max failures per ticket before giving up */
    maxTicketFailures: number;
    /** Max retries for in-function operations */
    maxRetries: number;
  };

  /** Per-reaction-type retry strategies for Guardian */
  retryStrategies: {
    ciFailed: { retries: number; escalateAfterMs: number };
    mergeConflicts: { retries: number; escalateAfterMs: number };
    stale: { retries: number; escalateAfterMs: number };
    feedbackPending: { retries: number; escalateAfterMs: number };
  };

  /** Query and result limits */
  queryLimits: {
    /** Max PRs to list from GitHub (default: 50) */
    prList: number;
    /** Max Slack channels to list (default: 200) */
    slackChannelList: number;
    /** Max Slack messages to fetch (default: 50) */
    slackFetchMessages: number;
    /** Memory search result limit (default: 10) */
    memorySearch: number;
    /** Gotcha search result limit (default: 5) */
    gotchaSearch: number;
    /** Max Slack thread scan iterations (default: 3) */
    maxThreadScans: number;
    /** Recent activity cap for metrics (default: 100) */
    recentActivityCap: number;
    /** Error message substring limit for logging (default: 200) */
    errorSubstringLimit: number;
  };
}

/**
 * Guardian merge lifecycle configuration (CLI-level).
 * Controls the automated PR merge pipeline behavior.
 * Stored in .traqr/config.json under the `guardian` key.
 */
export interface GuardianConfig {
  /** Whether Guardian is enabled (env: GUARDIAN_ENABLED) */
  enabled: boolean;

  /** Dry-run mode — actions logged but not executed (env: GUARDIAN_DRY_RUN) */
  dryRun: boolean;

  /** GitHub label that identifies PRs for Guardian to manage */
  prLabel: string;

  /** Phase timeout durations (ms) — auto-reset if stuck */
  phaseTimeouts: {
    /** Rebase phase timeout (default: 5min) */
    rebasing: number;
    /** Merge phase timeout (default: 30min) */
    merging: number;
    /** Conflict resolution phase timeout (default: 30min) */
    resolving: number;
  };

  /** Linear label configuration for ticket lifecycle */
  labels: {
    /** Label for tickets ready for agent pickup */
    agentReady: string;
    /** Label applied when agent claims a ticket */
    agentClaimed: { name: string; color: string };
    /** Label indicating ticket has an implementation plan */
    hasPlan: string;
  };
}

/**
 * Default daemon configuration.
 * All timing values tuned from production experience.
 */
export function getDefaultDaemonConfig(projectName: string): DaemonConfig {
  const prefix = projectName || 'traqr';
  return {
    apiBase: 'http://localhost:3000/api',
    paths: {
      processed: `/tmp/${prefix}-daemon-processed.json`,
      processedIssues: `/tmp/${prefix}-daemon-processed-issues.json`,
      plans: `/tmp/${prefix}-daemon-plans.json`,
      questionQueue: `/tmp/${prefix}-claude-tasks.json`,
      answeredQuestions: `/tmp/${prefix}-answered-questions.json`,
      processedAnalytics: `/tmp/${prefix}-daemon-analytics-processed.json`,
      metrics: `/tmp/${prefix}-automation-metrics.json`,
      guardianTemp: '.guardian-tmp',
    },
    intervals: {
      poll: 10_000,
      taskPoll: 30_000,
      guardian: 60_000,
      question: 60_000,
      analytics: 60_000,
      approvalCheck: 30_000,
      trafficCheck: 15 * 60_000,
      healthCheck: 30 * 60_000,
      syncCheck: 300_000,
      heartbeat: 60_000,
    },
    timeouts: {
      defaultFetch: 30_000,
      quickFetch: 3_000,
      git: 30_000,
      gitQuick: 5_000,
      gitRemove: 15_000,
      planApproval: 5 * 60_000,
      implementation: 30 * 60_000,
      toolCallStall: 5 * 60_000,
      npmBuild: 120_000,
      planApprovalTTL: 24 * 60 * 60_000,
      pauseExpiration: 2 * 60 * 60_000,
      reworkDetection: 30 * 60_000,
      perFileAdaptive: 3 * 60_000,
      maxAdaptive: 30 * 60_000,
      divergenceCache: 25_000,
      minApprovalWait: 30_000,
    },
    concurrency: {
      maxTasks: 2,
      maxTicketFailures: 3,
      maxRetries: 3,
    },
    retryStrategies: {
      ciFailed: { retries: 2, escalateAfterMs: 15 * 60_000 },
      mergeConflicts: { retries: 1, escalateAfterMs: 10 * 60_000 },
      stale: { retries: 2, escalateAfterMs: 10 * 60_000 },
      feedbackPending: { retries: 1, escalateAfterMs: 30 * 60_000 },
    },
    queryLimits: {
      prList: 50,
      slackChannelList: 200,
      slackFetchMessages: 50,
      memorySearch: 10,
      gotchaSearch: 5,
      maxThreadScans: 3,
      recentActivityCap: 100,
      errorSubstringLimit: 200,
    },
  };
}

/**
 * Default guardian configuration.
 * Safe defaults: disabled, dry-run on, conservative timeouts.
 */
export const DEFAULT_GUARDIAN_CONFIG: GuardianConfig = {
  enabled: false,
  dryRun: true,
  prLabel: 'daemon-pr',
  phaseTimeouts: {
    rebasing: 5 * 60_000,
    merging: 30 * 60_000,
    resolving: 30 * 60_000,
  },
  labels: {
    agentReady: 'agent-ready',
    agentClaimed: { name: 'agent-claimed', color: '#E67E22' },
    hasPlan: 'has-plan',
  },
};

// ============================================================
// Design DNA Configuration
// ============================================================

export interface DesignPalette {
  primary: string;
  secondary: string;
  accent: string;
  background: string;
  foreground: string;
  card: string;
  border: string;
  muted: string;
}

export interface DesignConfig {
  /** Design flavor preset */
  flavor: 'terminal' | 'playful' | 'minimal' | 'bold' | 'custom';
  /** Light mode color palette */
  palette: DesignPalette;
  /** Dark mode overrides (bg, fg, card, border, muted) */
  darkPalette?: {
    background: string;
    foreground: string;
    card: string;
    border: string;
    muted: string;
  };
  /** Font configuration */
  fonts: {
    sans: string;
    mono: string;
    /** Google Fonts import names, e.g. ['Inter', 'JetBrains_Mono'] */
    googleFonts: string[];
  };
  /** Border radius level */
  borderRadius: 'sharp' | 'medium' | 'rounded' | 'pill';
  /** Animation intensity */
  animations: 'none' | 'subtle' | 'smooth' | 'bouncy';
  /** Shadow intensity */
  shadows: 'none' | 'soft' | 'medium' | 'dramatic';
  /** Whether to include framer-motion dependency */
  useFramerMotion: boolean;
  /** Enable dark mode toggle support */
  darkMode: boolean;
  /** App display name shown in shell/sidebar */
  appDisplayName?: string;
}

/**
 * Border radius mapping per level.
 * Maps borderRadius setting to Tailwind classes at 4 sizes.
 */
