// ============================================================
// Required Services
// ============================================================

/**
 * Services that are always-on and non-skippable for Traqr projects.
 * During provisioning, these are processed in PASS 1.
 */
export const REQUIRED_SERVICES = ['github', 'supabase', 'posthog', 'vercel', 'slack'] as const;
export type RequiredService = (typeof REQUIRED_SERVICES)[number];

// ============================================================
// Main Configuration Interface
// ============================================================

export interface TraqrConfig {
  /** Schema version — '2.0.0' adds per-system tracking via `systems` map */
  version: '1.0.0' | '2.0.0';

  project: {
    /** Lowercase slug, e.g. "jiggycapital" */
    name: string;
    /** Display name, e.g. "Jiggy Capital" */
    displayName: string;
    /** Short description */
    description: string;
    /** Absolute path to main repo */
    repoPath: string;
    /** Absolute path to worktrees directory */
    worktreesPath: string;
    /** GitHub org/repo, e.g. "sean/jiggycapital" */
    ghOrgRepo: string;
    /** Framework detected (nextjs, node, python, rust, go, unknown) */
    framework?: string;
    /** Package manager (npm, yarn, pnpm, bun, pip, cargo) */
    packageManager?: string;
    /** Build command override */
    buildCommand?: string;
    /** Type-check command override */
    typecheckCommand?: string;
    /** Deployment platform (vercel, netlify, fly, railway, none) */
    deployPlatform?: string;
    /** Project type — determines which command steps apply (default: 'code') */
    type?: 'code' | 'life' | 'research';
  };

  /** Automation tier (0-4), derived from starterPack + customizations */
  tier: 0 | 1 | 2 | 3 | 4;

  /** Starter pack selection (entry point for wizard) */
  starterPack?: 'solo' | 'smart' | 'production' | 'full' | 'custom';

  /** Automation score (0-100), calculated from enabled features */
  automationScore?: number;

  /** Whether initialized in demo mode (no real API keys) */
  demo?: boolean;

  slots: {
    /** Number of marketing slots (default 1) */
    marketing?: number;
    /** Number of feature slots (default 5) */
    feature: number;
    /** Number of bugfix slots (default 5) */
    bugfix: number;
    /** Number of devops slots (default 5) */
    devops: number;
    /** Whether to include guardian/grunt slot (default true) */
    guardian?: boolean;
    /** Whether to include analysis slot (default false) */
    analysis: boolean;
  };

  ports: {
    /** Main repo port (default 3000) */
    main: number;
    /** First marketing port (default 3041) */
    marketingStart?: number;
    /** First feature port, increments by 1 (default 3001) */
    featureStart: number;
    /** First bugfix port, increments by 1 (default 3011) */
    bugfixStart: number;
    /** First devops port, increments by 1 (default 3021) */
    devopsStart: number;
    /** Guardian/grunt slot port (default 3031) */
    guardian?: number;
    /** Analysis slot port (default 3099) */
    analysis: number;
  };

  /** Short prefix for shell commands, e.g. "jiggy" -> jiggy-slots */
  prefix: string;

  /** 2-char alias prefix for multi-project shell aliases, e.g. "nk" -> nk1, nkc1 */
  aliasPrefix?: string;

  /** KV key namespace prefix for multi-project isolation, e.g. "nooktraqr" */
  kvPrefix?: string;

  /** Env var for authorized push, e.g. "JIGGYCAPITAL_SHIP_AUTHORIZED" */
  shipEnvVar: string;

  /** Session marker prefix, e.g. "jiggycapital" -> /tmp/jiggycapital-session-*.json */
  sessionPrefix: string;

  /** Co-author line for commits, e.g. "Claude Opus 4.6" */
  coAuthor: string;

  /** Memory configuration */
  memory?: {
    /** Memory provider: 'supabase' (full pgvector), 'local' (CLAUDE.md only), 'none' */
    provider: 'supabase' | 'local' | 'none';
    /** Memory API base URL, e.g. "https://nooktraqr.com/api" */
    apiBase?: string;
    /** Project slug in memory system */
    projectSlug?: string;
    /** Enable voice profile extraction */
    voiceProfiles?: boolean;
    /** Enable cross-project learning */
    crossProject?: boolean;
  };

  /** Obsidian vault configuration */
  vault?: {
    /** Absolute path to Obsidian vault root (e.g., '/Users/sean/Documents/Obsidian Vault') */
    path: string;
  };

  /** Issue tracking configuration */
  issues?: {
    /** Issue tracker provider */
    provider: 'linear' | 'github' | 'gitlab' | 'none';
    /** Linear team ID (required if provider is linear) */
    linearTeamId?: string;
    /** Linear workspace slug for URLs, e.g. "traqr-enterprises" → linear.app/traqr-enterprises/... */
    linearWorkspaceSlug?: string;
    /** Map of team key → team UUID for multi-team workspaces, e.g. { NTQ: "uuid1", TRQ: "uuid2" } */
    linearTeamMap?: Record<string, string>;
    /** Map of team key → Slack channel prefix, e.g. { NTQ: "nk", TRQ: "trq" } */
    channelPrefixMap?: Record<string, string>;
    /** Project ticket prefix for PR body parsing, e.g. "NTQ" for NookTraqr */
    ticketPrefix?: string;
    /** Enable plan-dispatch workflow */
    planDispatch?: boolean;
    /** Auto-create labels (agent-ready, has-plan, stale-*) */
    autoLabels?: boolean;
  };

  /** VCS (Version Control System) provider configuration */
  vcs?: {
    /** VCS provider: github or gitlab. Drives template conditionals and CLI tool selection. */
    provider: 'github' | 'gitlab';
    /** GitLab numeric project ID (required for GitLab API calls) */
    projectId?: string;
    /** Base URL for self-hosted instances (e.g., 'https://gitlab.aws.dev'). Defaults to github.com/gitlab.com */
    baseUrl?: string;
    /** Merge strategy: squash, fast-forward, or merge commit */
    mergeStrategy?: 'squash' | 'fast-forward' | 'merge';
    /** Enable auto-merge (GitHub: gh pr merge --auto, GitLab: merge_when_pipeline_succeeds) */
    autoMerge?: boolean;
    /** Enable primed-session pattern: GET before POST for corporate auth cookie establishment */
    primedSession?: boolean;
    /** Delete source branch after merge (GitLab setting) */
    removeSourceBranch?: boolean;
  };

  /** Notification configuration */
  notifications?: {
    /** Slack integration level */
    slackLevel: 'none' | 'basic' | 'standard' | 'full';
    /** Channel prefix for per-project channels (e.g., 'nk' for NookTraqr) */
    slackChannelPrefix?: string;
    /** Slack channel for PR notifications / merge buttons */
    slackDeployChannel?: string;
    /** Slack channel for triage/errors/Dev Inbox */
    slackTriageChannel?: string;
    /** Slack channel for analytics/signups */
    slackAnalyticsChannel?: string;
    /** Slack channel for user feedback log */
    slackFeedbackChannel?: string;
    /** Slack channel for marketing/newsletters */
    slackMarketingChannel?: string;
    /** Slack channel for archived threads */
    slackArchiveChannel?: string;
    /** Slack channel for ideas sounding board */
    slackIdeasChannel?: string;
    /** Slack channel for memory/learning notifications */
    slackMemoryChannel?: string;
    /** Slack channel for signup notifications */
    slackSignupsChannel?: string;
    /** Slack channel for control center status */
    slackControlCenterChannel?: string;
    /** Slack channel for cross-project dashboard aggregation */
    slackDashboardChannel?: string;
    /** Enable Dev Inbox (natural language ticket creation in Slack) */
    devInbox?: boolean;
    /** Enable Vibe Chat (brainstorming sessions in Slack threads) */
    vibeChat?: boolean;
  };

  /** Monitoring configuration */
  monitoring?: {
    /** Error tracking: sentry, axiom, or none */
    errorTracking: 'sentry' | 'axiom' | 'none';
    /** Analytics: posthog or none */
    analytics: 'posthog' | 'none';
    /** Uptime monitoring: checkly, betterstack, both, or none */
    uptime: 'checkly' | 'betterstack' | 'both' | 'none';
    /** Built-in user feedback widget */
    feedbackWidget: boolean;
    /** Observability: axiom or none */
    observability?: 'axiom' | 'none';
  };

  /** Auth provider configuration (per-project) */
  auth?: {
    /** Authentication provider */
    provider: 'firebase' | 'supabase' | 'clerk' | 'custom' | 'none';
  };

  /** Edge compute / KV configuration */
  edge?: {
    /** Edge provider */
    provider: 'cloudflare' | 'none';
    /** Cloudflare KV namespace ID (if provisioned) */
    kvNamespaceId?: string;
  };

  /** Email/marketing configuration */
  email?: {
    /** Email provider: resend or none */
    provider: 'resend' | 'none';
    /** Enabled email templates */
    templates: Array<
      'bug-fix' | 'feature-shipped' | 'welcome' | 'feedback-request' | 'weekly-recap' | 'marketing'
    >;
    /** Enable the full user feedback loop (bug -> fix -> email user) */
    feedbackLoop: boolean;
  };

  /** Cron job configuration — grouped by category */
  crons?: {
    /** Development health crons (slot status, stale branch cleanup, etc.) */
    devHealth: boolean;
    /** Analytics crons (engagement reports, traffic monitor, funnel analysis) */
    analytics: boolean;
    /** Issue tracking crons (ticket aging, backlog digest, SLA alerts) */
    issueTracking: boolean;
    /** Monitoring crons (proactive alerts, error digests) */
    monitoring: boolean;
    /** Memory system crons (learning synthesis, contradiction check) */
    memory: boolean;
    /** Marketing crons (newsletter schedule, unsubscribe cleanup) */
    marketing: boolean;
    /** Agent system crons (daemon health, session analysis) */
    agentSystem: boolean;
    /** Digest & report crons (daily/weekly summaries) */
    digests: boolean;
  };

  /** Daemon orchestration configuration (intervals, timeouts, concurrency) */
  daemon?: Partial<DaemonConfig>;

  /** Guardian merge lifecycle configuration */
  guardian?: Partial<GuardianConfig>;

  /** Design DNA configuration (visual flavor, palette, fonts, animations) */
  design?: DesignConfig;

  /** Monorepo sub-app configuration */
  monorepo?: {
    /** Whether this project is a monorepo with multiple apps */
    enabled: boolean;
    /** Directories containing apps (e.g. ['apps/nooktraqr', 'apps/platform']) */
    appDirs: string[];
    /** Per-app configuration overrides */
    apps: Record<string, {
      /** Human-readable app name */
      displayName: string;
      /** App directory relative to monorepo root (e.g. 'apps/pokotraqr') */
      appDir: string;
      /** Port offset for slot allocation (e.g. 0=3001, 1000=4001 for feature1) */
      portOffset: number;
      /** Auth provider override for this app */
      auth?: { provider: 'firebase' | 'supabase' | 'clerk' | 'custom' | 'none' };
      /** Framework override for this app */
      framework?: string;
      /** Workspace dependencies (e.g. ['@traqr/core', '@pokotraqr/data']) */
      workspaceDeps?: string[];
      /** Companion data package name (e.g. '@pokotraqr/data') */
      companionPackage?: string;
      /** Per-app Linear team ID (discovered or created during sub-app init) */
      linearTeamId?: string;
      /** Per-app ticket prefix for PR body parsing (e.g. "PKT") */
      ticketPrefix?: string;
      /** Per-app Slack channel prefix (e.g. "pk") */
      slackChannelPrefix?: string;
      /** Per-app Slack channels — maps purpose to channel name */
      slackChannels?: Record<string, string>;
    }>;
  };

  /** Template source configuration (for cross-project init) */
  templateSource?: {
    /** Where to load templates from */
    mode: 'local' | 'api';
    /** API URL for remote template loading (required if mode is 'api') */
    apiUrl?: string;
  };

  /** Service provisioning state — tracks how each service was set up */
  provisioning?: Record<string, {
    /** How the service was provisioned */
    method: 'mcp' | 'manual' | 'demo';
    /** ISO timestamp of provisioning */
    provisionedAt?: string;
    /** Env vars captured during provisioning */
    envVars?: string[];
  }>;

  /** Per-system skill tracking (v2) — records version, last applied, and audit state per sub-skill */
  systems?: Record<string, {
    /** Version of the sub-skill that last configured this system */
    skillVersion: string;
    /** ISO timestamp of when the sub-skill was last run in setup/upgrade mode */
    lastApplied: string;
    /** Last audit result, if audit has been run */
    lastAudit?: {
      timestamp: string;
      status: 'pass' | 'warn' | 'fail';
      gaps: number;
    };
  }>;
}

/**
 * Provisioning dependency tiers — services must be provisioned in this order.
 * Tier 1 services are provisioned first (others may depend on them).
 * All 11 services are represented across 4 tiers.
 */
export const PROVISIONING_TIERS: Array<{ tier: number; services: string[] }> = [
  { tier: 1, services: ['github', 'gitlab', 'supabase'] },
  { tier: 2, services: ['linear', 'slack', 'sentry'] },
  { tier: 3, services: ['posthog', 'resend', 'cloudflare', 'firebase', 'clerk'] },
  { tier: 4, services: ['vercel', 'axiom'] },
];

/**
 * Return services that need provisioning for a given config, in dependency order.
 * Returns two lists: required (always-on) and selected (user choices), both in tier order.
 */
export function getProvisioningOrder(config: TraqrConfig): string[] {
  const needed: string[] = [];
  for (const { services } of PROVISIONING_TIERS) {
    for (const svc of services) {
      switch (svc) {
        case 'github':
          // Required when VCS is GitHub (or no VCS specified — backward compat)
          if (!config.vcs?.provider || config.vcs.provider === 'github') needed.push(svc);
          break;
        case 'gitlab':
          // Required when VCS is GitLab
          if (config.vcs?.provider === 'gitlab') needed.push(svc);
          break;
        case 'supabase':
          // Required — database + memory foundation
          needed.push(svc);
          break;
        case 'posthog':
          // Required — analytics non-negotiable
          if (config.monitoring?.analytics !== 'none') needed.push(svc);
          break;
        case 'vercel':
          // Required — deployment platform
          if (config.project.deployPlatform === 'vercel' || config.project.deployPlatform === undefined) needed.push(svc);
          break;
        case 'slack':
          // Required — notification hub
          if (config.notifications?.slackLevel && config.notifications.slackLevel !== 'none') needed.push(svc);
          break;
        case 'linear':
          if (config.issues?.provider === 'linear') needed.push(svc);
          break;
        case 'sentry':
          if (config.monitoring?.errorTracking === 'sentry') needed.push(svc);
          break;
        case 'resend':
          if (config.email?.provider === 'resend') needed.push(svc);
          break;
        case 'cloudflare':
          if (config.edge?.provider === 'cloudflare' || config.daemon) needed.push(svc);
          break;
        case 'firebase':
          if (config.auth?.provider === 'firebase') needed.push(svc);
          break;
        case 'clerk':
          if (config.auth?.provider === 'clerk') needed.push(svc);
          break;
        case 'axiom':
          if (config.monitoring?.observability === 'axiom') needed.push(svc);
          break;
      }
    }
  }
  return needed;
}

/**
 * Split provisioning order into required (PASS 1) and selected (PASS 2) services.
 */
export function getProvisioningPasses(config: TraqrConfig): { pass1: string[]; pass2: string[] } {
  const all = getProvisioningOrder(config);
  const requiredSet = new Set<string>(REQUIRED_SERVICES);
  return {
    pass1: all.filter(s => requiredSet.has(s)),
    pass2: all.filter(s => !requiredSet.has(s)),
  };
}

