/**
 * Build provisioning state for demo mode.
 * All selected services get `method: 'demo'` with mock env vars.
 */
export function getDemoProvisioningState(
  config: TraqrConfig
): Record<string, { method: 'demo'; provisionedAt: string; envVars: string[] }> {
  const services = getProvisioningOrder(config);
  const now = new Date().toISOString();
  const state: Record<string, { method: 'demo'; provisionedAt: string; envVars: string[] }> = {};

  for (const svc of services) {
    const vars = DEMO_ENV_VARS[svc];
    if (vars) {
      state[svc] = {
        method: 'demo',
        provisionedAt: now,
        envVars: Object.keys(vars),
      };
    }
  }

  return state;
}

