/**
 * Calculate automation score (0-100) from config.
 */
export function calculateAutomationScore(config: TraqrConfig): number {
  let score = 0;

  // Slots: up to 15 points
  const totalSlots = (config.slots.marketing || 0) + config.slots.feature + config.slots.bugfix + config.slots.devops + (config.slots.guardian ? 1 : 0) + (config.slots.analysis ? 1 : 0);
  score += Math.min(15, totalSlots * 2);

  // Memory: up to 20 points
  if (config.memory?.provider === 'supabase') {
    score += 15;
    if (config.memory.crossProject) score += 3;
    if (config.memory.voiceProfiles) score += 2;
  } else if (config.memory?.provider === 'local') {
    score += 10;
  }

  // Issues: up to 15 points
  if (config.issues?.provider === 'linear') {
    score += 10;
    if (config.issues.planDispatch) score += 3;
    if (config.issues.autoLabels) score += 2;
  } else if (config.issues?.provider === 'github') {
    score += 7;
    if (config.issues.planDispatch) score += 3;
  } else if (config.issues?.provider === 'gitlab') {
    score += 7;
    if (config.issues.planDispatch) score += 3;
  }

  // Slack: up to 15 points
  if (config.notifications?.slackLevel === 'full') {
    score += 15;
  } else if (config.notifications?.slackLevel === 'standard') {
    score += 10;
  } else if (config.notifications?.slackLevel === 'basic') {
    score += 5;
  }

  // Monitoring: up to 15 points
  if (config.monitoring) {
    if (config.monitoring.errorTracking !== 'none') score += 4;
    if (config.monitoring.analytics !== 'none') score += 4;
    if (config.monitoring.uptime === 'both') score += 4;
    else if (config.monitoring.uptime !== 'none') score += 3;
    if (config.monitoring.feedbackWidget) score += 3;
    // Observability: +2 bonus
    if (config.monitoring.observability === 'axiom') score += 2;
  }

  // Auth: up to 3 points
  if (config.auth?.provider && config.auth.provider !== 'none') {
    score += 3;
  }

  // Edge: up to 3 points
  if (config.edge?.provider === 'cloudflare') {
    score += 3;
  }

  // Email: up to 10 points
  if (config.email) {
    if (config.email.provider !== 'none') score += 3;
    score += Math.min(5, config.email.templates.length);
    if (config.email.feedbackLoop) score += 2;
  }

  // Crons: up to 10 points
  if (config.crons) {
    const enabledCrons = Object.values(config.crons).filter(Boolean).length;
    score += Math.min(10, enabledCrons * 1.25);
  }

  return Math.min(100, Math.round(score));
}

// ============================================================
// Config v2 Migration
// ============================================================

/**
 * Migrate a v1 config to v2 by adding the `systems` tracking map.
 * Idempotent — returns the config unchanged if already v2.
 * Preserves all existing fields.
 */
export function migrateConfigV1ToV2(config: TraqrConfig): TraqrConfig {
  if (config.version === '2.0.0') return config;
  return {
    ...config,
    version: '2.0.0' as const,
    systems: {},
  };
}

/**
 * Type guard: returns true if the config has been migrated to v2
 * (has version 2.0.0 and a systems map).
 */
export function isConfigV2(config: TraqrConfig): boolean {
  return config.version === '2.0.0' && config.systems !== undefined;
}
